    sw = x,
    north = \bar {f},
    south = f,
    se = y,
  }
  \node  (u') [above left = 1.5cm of nw,xshift=-.5cm] {$\bar {u}$};
  \node  (u) [above left = 1.5cm of sw,xshift=-.5cm] {$u$};
  \draw [lies over] (u') to (u);
  \draw [->,bend left=30] (u') to node [sloped,above] {$\bar {h}$} (ne);
  \draw [->] (u) to node [sloped,below] {$m$} (sw);
  \draw [->,exists] (u') to (nw);
\end {tikzpicture}

